import React from 'react';
import { useNavigate } from 'react-router-dom';
import { FaCarSide, FaCreditCard, FaHistory } from 'react-icons/fa';

const Payments = () => {
    const navigate = useNavigate();
a
    return (
        <div style={containerStyle}>
            <aside style={sidebarStyle}>
                <div style={logoContainer}>
                    <FaCarSide style={carIconStyle} />
                    <h1 style={logoTextStyle}>Ucab</h1>
                </div>
                <nav style={{ flex: 1 }}>
                    <div onClick={() => navigate('/profile')} style={navItemStyle}>👤 Profile</div>
                    <div onClick={() => navigate('/booking')} style={navItemStyle}>🚗 Book a Ride</div>
                    <div onClick={() => navigate('/payments')} style={activeNavItemStyle}>💳 Payments</div>
                    <div onClick={() => navigate('/support')} style={navItemStyle}>⚙️ Support</div>
                </nav>
            </aside>

            <main style={mainAreaStyle}>
                <h2 style={{ fontWeight: '700', marginBottom: '30px' }}>Payment Settings</h2>
                
                <div style={cardStyle}>
                    <h4 style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                        <FaCreditCard color="#0052cc" /> Saved Methods
                    </h4>
                    <div style={paymentItem}>
                        <span>💳 VISA **** 4242</span>
                        <span style={tagStyle}>Default</span>
                    </div>
                    <button style={addBtnStyle}>+ Add New Payment Method</button>
                </div>

                <div style={cardStyle}>
                    <h4 style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                        <FaHistory color="#0052cc" /> Recent Transactions
                    </h4>
                    <p style={{ color: '#64748b', textAlign: 'center', marginTop: '20px' }}>
                        No transactions found in the last 30 days.
                    </p>
                </div>
            </main>
        </div>
    );
};

// --- Styles (Same as Booking for consistency) ---
const containerStyle = { display: 'flex', height: '100vh', backgroundColor: '#f8f9fc', fontFamily: "'Segoe UI', sans-serif" };
const sidebarStyle = { width: '280px', backgroundColor: '#fff', padding: '40px 24px', borderRight: '1px solid #edf2f7', display: 'flex', flexDirection: 'column' };
const logoContainer = { display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '40px' };
const carIconStyle = { fontSize: '32px', color: '#0052cc' };
const logoTextStyle = { fontSize: '28px', fontWeight: 'bold', color: '#1e293b' };
const navItemStyle = { padding: '14px 16px', cursor: 'pointer', borderRadius: '8px', color: '#64748b', marginBottom: '8px' };
const activeNavItemStyle = { ...navItemStyle, backgroundColor: '#f0f7ff', color: '#0052cc', fontWeight: '600' };
const mainAreaStyle = { flex: 1, padding: '40px' };
const cardStyle = { backgroundColor: '#fff', padding: '30px', borderRadius: '20px', boxShadow: '0 4px 12px rgba(0,0,0,0.05)', marginBottom: '30px' };
const paymentItem = { display: 'flex', justifyContent: 'space-between', padding: '18px', border: '1.5px solid #e2e8f0', borderRadius: '12px', marginTop: '15px' };
const tagStyle = { backgroundColor: '#e1effe', color: '#1e42af', padding: '4px 10px', borderRadius: '6px', fontSize: '12px', fontWeight: 'bold' };
const addBtnStyle = { marginTop: '25px', padding: '12px 24px', backgroundColor: '#0052cc', color: '#fff', border: 'none', borderRadius: '10px', cursor: 'pointer', fontWeight: '600' };

export default Payments;
